import { GoogleGenAI, Type } from "@google/genai";
import { SafeScanResponse, RecallAlert, AppSettings } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeReceipt(
    receiptText: string, 
    recalls: RecallAlert[], 
    settings: AppSettings
  ): Promise<SafeScanResponse> {
    const model = 'gemini-3-flash-preview';

    const systemInstruction = `
      Tu es le moteur d'analyse critique de l'application "SafeScan".
      Ton rôle est de comparer les produits d'un ticket de caisse (souvent abrégés) avec une base de données de rappels produits.

      MISSIONS :
      1. ANALYSE : Identifier chaque produit du ticket.
      2. MATCHING INTELLIGENT : Utiliser le fuzzy matching pour les abréviations.
      3. VÉRIFICATION DES LOTS : Si un lot est présent (ex: "LOT: XXX"), l'utiliser comme clé prioritaire.
      4. ÉVALUATION DU RISQUE : Critique (danger immédiat), Modéré (précaution), Info (lot différent mais produit identique).
      5. FILTRE SANTÉ : ${settings.detectSugars ? 'Signaler la présence de sirop de glucose ou de sucres ajoutés.' : 'Ne pas signaler les sucres.'}

      CONTRAINTES :
      - Ne jamais inventer d'alertes.
      - Renvoie une liste vide si aucune correspondance.
      - Sois ultra-précis sur les marques.
    `;

    const prompt = `
      DONNÉES DU TICKET :
      ${receiptText}

      FLUX DE RAPPELS OFFICIELS :
      ${JSON.stringify(recalls, null, 2)}

      Renvoie le résultat en JSON strict selon le schéma fourni.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model,
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              analysis_summary: {
                type: Type.OBJECT,
                properties: {
                  items_scanned: { type: Type.NUMBER },
                  alerts_found: { type: Type.NUMBER }
                },
                required: ["items_scanned", "alerts_found"]
              },
              alerts: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    receipt_item: { type: Type.STRING },
                    official_recall_name: { type: Type.STRING },
                    match_confidence: { type: Type.STRING },
                    risk_level: { type: Type.STRING },
                    danger_reason: { type: Type.STRING },
                    health_warning: { type: Type.STRING },
                    action_required: { type: Type.STRING }
                  },
                  required: ["receipt_item", "official_recall_name", "match_confidence", "risk_level", "danger_reason", "action_required"]
                }
              }
            },
            required: ["analysis_summary", "alerts"]
          }
        }
      });

      const text = response.text || '{}';
      return JSON.parse(text) as SafeScanResponse;
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw error;
    }
  }
}

import React, { useState, useCallback, useMemo } from 'react';
import { 
  ShieldAlert, 
  ShieldCheck, 
  Search, 
  Settings, 
  AlertTriangle, 
  Info, 
  XCircle, 
  Camera, 
  FileText, 
  RefreshCcw,
  ExternalLink,
  ChevronRight
} from 'lucide-react';
import { GeminiService } from './services/geminiService';
import { OFFICIAL_RECALLS, RECEIPT_EXAMPLES } from './constants';
import { SafeScanResponse, AppSettings } from './types';

const App: React.FC = () => {
  const [receiptText, setReceiptText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<SafeScanResponse | null>(null);
