    if (!receiptText.trim()) {
      setError("Veuillez saisir le texte d'un ticket ou utiliser un exemple.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const data = await geminiService.analyzeReceipt(receiptText, OFFICIAL_RECALLS, settings);
      setResult(data);
    } catch (err) {
      setError("Une erreur est survenue lors de l'analyse. Vérifiez votre connexion.");
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const loadExample = (text: string) => {
    setReceiptText(text);
    setError(null);
  };

  const getRiskColor = (level: string) => {
    switch (level) {
      case 'Critique': return 'text-red-600 bg-red-50 border-red-200';
      case 'Modéré': return 'text-amber-600 bg-amber-50 border-amber-200';
      case 'Info': return 'text-blue-600 bg-blue-50 border-blue-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  const getRiskIcon = (level: string) => {
    switch (level) {
      case 'Critique': return <XCircle className="w-5 h-5" />;
      case 'Modéré': return <AlertTriangle className="w-5 h-5" />;
      case 'Info': return <Info className="w-5 h-5" />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-white border-b border-slate-200 px-4 py-3 shadow-sm">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <ShieldCheck className="w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">SafeScan</h1>
          </div>
          <button 
            onClick={() => setShowSettings(!showSettings)}
            className="p-2 text-slate-500 hover:bg-slate-100 rounded-full transition-colors"
          >
            <Settings className="w-6 h-6" />
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8 space-y-8">
        {/* Intro */}
        <section className="text-center space-y-4">
          <h2 className="text-3xl font-extrabold text-slate-900 sm:text-4xl">
            Protegez votre <span className="text-indigo-600">Santé</span>
          </h2>
          <p className="text-slate-600 text-lg max-w-xl mx-auto">
            Analysez instantanément vos tickets de caisse pour détecter d'éventuels rappels sanitaires et ingrédients nocifs.
          </p>
        </section>

        {/* Settings Overlay */}
        {showSettings && (
          <div className="bg-white border border-slate-200 rounded-2xl p-6 shadow-xl animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-lg flex items-center gap-2">
                <Settings className="w-5 h-5" /> Préférences de santé
              </h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-slate-600">
                <XCircle className="w-5 h-5" />
              </button>
            </div>
            <label className="flex items-center gap-3 cursor-pointer group">
              <div className="relative inline-flex items-center cursor-pointer">
                <input 
                  type="checkbox" 
                  className="sr-only peer"
                  checked={settings.detectSugars}
                  onChange={() => setSettings(prev => ({ ...prev, detectSugars: !prev.detectSugars }))}
                />
                <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-indigo-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
              </div>
              <span className="text-slate-700 font-medium">Détecter les sucres ajoutés & sirop de glucose</span>
            </label>
          </div>
        )}

        {/* Scanner Section */}
        <section className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <label className="text-sm font-semibold uppercase tracking-wider text-slate-500 flex items-center gap-2">
                <FileText className="w-4 h-4" /> Texte du ticket
              </label>
              <div className="flex gap-2">
                {RECEIPT_EXAMPLES.map((ex, idx) => (
                  <button 
                    key={idx}
