                    className="text-xs bg-slate-100 hover:bg-slate-200 px-3 py-1 rounded-full text-slate-600 transition-colors"
                  >
                    Exemple {idx + 1}
                  </button>
                ))}
              </div>
            </div>

            <textarea
              className="w-full h-40 p-4 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none text-slate-800 font-mono text-sm"
              placeholder="Collez le texte extrait de votre ticket ou scannez le code-barres..."
              value={receiptText}
              onChange={(e) => setReceiptText(e.target.value)}
            />

            <div className="mt-6 flex flex-col sm:flex-row gap-3">
              <button
                onClick={handleAnalyze}
                disabled={isAnalyzing}
                className={`flex-1 flex items-center justify-center gap-2 py-4 px-6 rounded-xl font-bold text-white shadow-lg transition-all ${
                  isAnalyzing 
                    ? 'bg-indigo-400 cursor-not-allowed' 
                    : 'bg-indigo-600 hover:bg-indigo-700 active:scale-95 shadow-indigo-200'
                }`}
              >
                {isAnalyzing ? (
                  <>
                    <RefreshCcw className="w-5 h-5 animate-spin" />
                    Analyse en cours...
                  </>
                ) : (
                  <>
                    <Search className="w-5 h-5" />
                    Lancer l'analyse critique
                  </>
                )}
              </button>

              <button 
                className="flex items-center justify-center gap-2 py-4 px-6 rounded-xl font-bold border border-slate-200 text-slate-700 hover:bg-slate-50 transition-all"
              >
                <Camera className="w-5 h-5" />
                OCR Scan
              </button>
            </div>

            {error && (
              <div className="mt-4 p-4 bg-red-50 border border-red-100 text-red-600 rounded-xl flex items-center gap-3">
                <ShieldAlert className="w-5 h-5" />
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}
          </div>
        </section>

        {/* Results Section */}
        {(isAnalyzing || result) && (
          <section className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between border-b border-slate-200 pb-2">
              <h3 className="text-xl font-bold text-slate-800">Résultats de l'analyse</h3>
              {result && (
                <span className="text-sm text-slate-500">
                  {result.analysis_summary.items_scanned} produits scannés
                </span>
              )}
            </div>

            {isAnalyzing && (
              <div className="flex flex-col items-center justify-center py-20 space-y-4">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                  <ShieldCheck className="w-8 h-8 text-indigo-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                </div>
                <p className="text-slate-500 font-medium animate-pulse">Comparaison avec la base de données gouvernementale...</p>
              </div>
            )}

            {result && (
              <div className="space-y-6">
                {result.alerts.length === 0 ? (
                  <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-3xl text-center space-y-4">
                    <div className="mx-auto bg-emerald-100 w-16 h-16 rounded-full flex items-center justify-center text-emerald-600">
                      <ShieldCheck className="w-10 h-10" />
                    </div>
                    <div>
                      <h4 className="text-xl font-bold text-emerald-800">Aucune alerte trouvée</h4>
                      <p className="text-emerald-700 opacity-80">
                        Vos produits semblent être sûrs selon les rappels sanitaires actuels.
                      </p>
                    </div>
                  </div>
                ) : (
                  <div className="grid gap-4">
                    <div className="bg-red-50 border border-red-100 p-4 rounded-xl flex items-center gap-3 mb-2">
                      <AlertTriangle className="w-6 h-6 text-red-600" />
                      <p className="text-red-800 font-semibold">
                        {result.alerts.length} point{result.alerts.length > 1 ? 's' : ''} d'attention détecté{result.alerts.length > 1 ? 's' : ''}.
                      </p>
                    </div>
                    {result.alerts.map((alert, idx) => (
                      <div 
                        key={idx} 
                        className="bg-white border border-slate-200 rounded-2xl overflow-hidden hover:shadow-md transition-all group"
                      >
                        <div className="flex flex-col md:flex-row">
                          {/* Risk Indicator Sidebar */}
                          <div className={`w-full md:w-2 ${getRiskColor(alert.risk_level).split(' ')[1]}`}></div>

                          <div className="p-5 flex-1 space-y-4">
                            <div className="flex flex-wrap items-start justify-between gap-3">
                              <div className="space-y-1">
                                <div className="flex items-center gap-2">
                                  <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold uppercase tracking-wider flex items-center gap-1.5 border ${getRiskColor(alert.risk_level)}`}>
                                    {getRiskIcon(alert.risk_level)}
                                    {alert.risk_level}
                                  </span>
                                  <span className="text-xs font-medium text-slate-400">Fiabilité: {alert.match_confidence}</span>
                                </div>
                                <h4 className="text-lg font-bold text-slate-900 leading-tight">
                                  {alert.official_recall_name}
                                </h4>
                                <p className="text-sm text-slate-500 flex items-center gap-1 italic">
                                  Identifié comme : "{alert.receipt_item}"
                                </p>
                              </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                              <div className="space-y-2">
                                <h5 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Motif du danger</h5>
                                <p className="text-slate-700 text-sm bg-slate-50 p-3 rounded-lg border border-slate-100">
                                  {alert.danger_reason}
                                </p>
                              </div>
                              <div className="space-y-2">
                                <h5 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Action requise</h5>
                                <p className="text-indigo-800 text-sm font-semibold bg-indigo-50 p-3 rounded-lg border border-indigo-100">
                                  {alert.action_required}
                                </p>
                              </div>
                            </div>

                            {alert.health_warning && (
                              <div className="bg-amber-50 border border-amber-100 rounded-lg p-3 flex items-start gap-2">
                                <Info className="w-4 h-4 text-amber-600 mt-0.5 shrink-0" />
                                <div className="text-xs text-amber-800 font-medium">
                                  <span className="font-bold">Alerte Santé :</span> {alert.health_warning}
                                </div>
                              </div>
                            )}

                            <div className="flex items-center justify-between pt-2 border-t border-slate-50">
                              <button className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center gap-1 group-hover:underline">
                                Plus de détails <ExternalLink className="w-3 h-3" />
                              </button>
                              <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-indigo-400 transition-colors" />
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </section>
        )}
      </main>

      {/* Footer Navigation (Mobile) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-6 py-3 md:hidden flex justify-around items-center z-40">
        <button className="flex flex-col items-center gap-1 text-indigo-600">
          <Search className="w-6 h-6" />
          <span className="text-[10px] font-bold">Analyser</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-slate-400">
          <AlertTriangle className="w-6 h-6" />
          <span className="text-[10px] font-bold">Rappels</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-slate-400">
          <Settings className="w-6 h-6" />
          <span className="text-[10px] font-bold">Profil</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

export interface RecallAlert {
