  autoSyncBank: boolean;
}

export interface ConnectedService {
  id: string;
  name: string;
  status: 'connected' | 'disconnected';
  type: 'bank' | 'loyalty' | 'nfc';
}

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { 
  ShieldAlert, 
  ShieldCheck, 
  Search, 
  Settings, 
  AlertTriangle, 
  Info, 
  XCircle, 
  Camera, 
  FileText, 
  RefreshCcw,
  ExternalLink,
  ChevronRight,
  CreditCard,
  Rss,
  Link as LinkIcon,
  CheckCircle2
} from 'lucide-react';
import { GeminiService } from './services/geminiService';
import { OFFICIAL_RECALLS, RECEIPT_EXAMPLES } from './constants';
import { SafeScanResponse, AppSettings, ConnectedService } from './types';

const App: React.FC = () => {
  const [receiptText, setReceiptText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isNfcScanning, setIsNfcScanning] = useState(false);
  const [result, setResult] = useState<SafeScanResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [settings, setSettings] = useState<AppSettings>({ detectSugars: true, autoSyncBank: false });
  const [showSettings, setShowSettings] = useState(false);
  const [activeTab, setActiveTab] = useState<'scan' | 'services'>('scan');

  const geminiService = useMemo(() => new GeminiService(), []);

  const [connectedServices, setConnectedServices] = useState<ConnectedService[]>([
    { id: '1', name: 'Ma Banque (DSP2)', status: 'disconnected', type: 'bank' },
    { id: '2', name: 'Liaison Ticket Dématérialisé', status: 'disconnected', type: 'nfc' },
  ]);

  const handleAnalyze = async (textToAnalyze: string = receiptText) => {
    if (!textToAnalyze.trim()) {
      setError("Veuillez saisir le texte d'un ticket ou utiliser le mode automatique.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const data = await geminiService.analyzeReceipt(textToAnalyze, OFFICIAL_RECALLS, settings);
      setResult(data);
    } catch (err) {
      setError("Une erreur est survenue lors de l'analyse.");
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const simulateNfcPayment = () => {
    setIsNfcScanning(true);
    setResult(null);

    // Simulation du temps de transaction NFC + Récupération API
    setTimeout(() => {
      const randomReceipt = RECEIPT_EXAMPLES[Math.floor(Math.random() * RECEIPT_EXAMPLES.length)];
      setReceiptText(randomReceipt);
      setIsNfcScanning(false);
      handleAnalyze(randomReceipt);
    }, 2500);
  };

  const toggleService = (id: string) => {
    setConnectedServices(services => services.map(s => 
      s.id === id ? { ...s, status: s.status === 'connected' ? 'disconnected' : 'connected' } : s
    ));
  };

  const getRiskColor = (level: string) => {
    switch (level) {
      case 'Critique': return 'text-red-600 bg-red-50 border-red-200';
      case 'Modéré': return 'text-amber-600 bg-amber-50 border-amber-200';
      case 'Info': return 'text-blue-600 bg-blue-50 border-blue-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  const getRiskIcon = (level: string) => {
    switch (level) {
      case 'Critique': return <XCircle className="w-5 h-5" />;
