import { GoogleGenAI, Type } from "@google/genai";
import { SafeScanResponse, RecallAlert, AppSettings } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeReceipt(
    receiptText: string, 
    recalls: RecallAlert[], 
    settings: AppSettings
  ): Promise<SafeScanResponse> {
    const model = 'gemini-3-flash-preview';

    const systemInstruction = `
      Tu es l'intelligence centrale de l'application "SafeScan", expert en sécurité alimentaire, anti-gaspillage et nutrition.

      MISSIONS :
      1. SÉCURITÉ : Compare avec la base RappelConso. Identifie NOM, MARQUE, LOT. Si lot match -> CRITIQUE.
      2. ANTI-GASPILLAGE : Estime la durée de vie des produits frais (ex: J+3 pour viande, J+7 pour yaourt).
      3. COACH NUTRITION : Détecte les ultra-transformés (sirop de glucose, additifs). 
         Propose une alternative magasin ET une recette "Fait maison" avec économie estimée.

      RÈGLES RGPD :
      - Recommandations locales uniquement.
      - Ne pas stocker d'habitudes nominatives.

      CONTRAINTES :
      - Bilan économique : Somme totale économisée (ex: "12.50€").
      - Procédure remboursement : Si alerte, écrire "Prête", sinon "Non applicable".
    `;

    const prompt = `
      DONNÉES DU TICKET :
      ${receiptText}

      FLUX DE RAPPELS OFFICIELS :
      ${JSON.stringify(recalls, null, 2)}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model,
        contents: prompt,
        config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              alerte_sanitaire: {
                type: Type.OBJECT,
                properties: {
                  produit: { type: Type.STRING },
                  marque: { type: Type.STRING },
                  lot_detecte: { type: Type.STRING },
                  statut: { type: Type.STRING, description: "CRITIQUE ou AUCUN" },
                  motif: { type: Type.STRING },
                  procedure_remboursement: { type: Type.STRING }
                },
                required: ["produit", "marque", "lot_detecte", "statut", "motif", "procedure_remboursement"]
              },
              gestion_frigo: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    article: { type: Type.STRING },
                    conso_avant: { type: Type.STRING },
                    conseil: { type: Type.STRING }
                  },
                  required: ["article", "conso_avant", "conseil"]
                }
              },
              optimisation_sante: {
                type: Type.OBJECT,
                properties: {
                  produit_analyse: { type: Type.STRING },
                  alerte_ingredient: { type: Type.STRING },
                  alternative_magasin: { type: Type.STRING },
                  option_fait_maison: {
                    type: Type.OBJECT,
                    properties: {
                      recette: { type: Type.STRING },
                      economie_estimee: { type: Type.STRING }
                    },
                    required: ["recette", "economie_estimee"]
                  }
                },
                required: ["produit_analyse", "alerte_ingredient", "alternative_magasin", "option_fait_maison"]
              },
              bilan_economique: { type: Type.STRING }
            },
            required: ["alerte_sanitaire", "gestion_frigo", "optimisation_sante", "bilan_economique"]
          }
        }
      });

      return JSON.parse(response.text || '{}') as SafeScanResponse;
    } catch (error) {
      console.error("Analysis Error:", error);
      throw error;
    }
  }
}

